previewCss:
.darma-loader-darma-custom-401 {color: var(--loader-color, #ca8a04);
  --loader-secondary-color: #fde047;
  --loader-bg: #ffffff;
  display: inline-grid;
  font-size: 50px;
}.darma-loader-darma-custom-401:before,.darma-loader-darma-custom-401:after {content: "💯";
  grid-area: 1/1;
}.darma-loader-darma-custom-401:before {animation: darma-loader-darma-custom-401-l10 1s infinite;
}@keyframes darma-loader-darma-custom-401-l10 {to {transform: scale(1.8);
  opacity:0}}

